import axios from 'axios';

(async () => {
  const baseUrl = 'http://localhost:3010';
  const path = '/clients';
  const url = `${baseUrl}${path}`;

  const response = await axios({
    method: 'get',
    headers: {
      'x-api-key': 'a3cad2343dc06dec39d967c1a836d426c754e7edec533be2ce5a3e8139d0a67f'
    },
    url
  });
  const data = response.data;
  console.log(data);
})();
